4	{
5	    public class BlockPositionInfo
6	    {
7	        public BlockPositionInfo(Vector3Int originalPos, BlockDirection blockDirection, Vector3Int blockSize)
8	        {
9	            OriginalPos = originalPos;
10	            BlockDirection = blockDirection;
11	            BlockSize = blockSize;
12	            
13	            MaxPos = CalcBlockMaxPos(originalPos, blockDirection, BlockSize);
14	        }
15	        
16	        /// <summary>
17	        ///     オリジナル座標は常に左下（ブロックが専有する範囲の最小の座標）になる
18	        /// </summary>
19	        public Vector3Int OriginalPos { get; }
20	        
21	        public Vector3Int BlockSize { get; }
22	        
23	        public Vector3Int MinPos => OriginalPos;
24	        public Vector3Int MaxPos { get; }
25	        
26	        public BlockDirection BlockDirection { get; }
27	        
28	        /// <summary>
29	        ///     サーバー側管理のブロックの最大座標を計算する
30	        ///     これはどのグリッドにブロックが存在しているかということに使われるため、サイズ 1,1 の場合、originとmaxの値はおなじになる
31	        /// </summary>
32	        public static Vector3Int CalcBlockMaxPos(Vector3Int originPos, BlockDirection direction, Vector3Int blockSize)
33	        {
34	            var addPos = Vector3Int.zero;
35	            switch (direction)
36	            {
37	                case BlockDirection.UpNorth:
38	                case BlockDirection.UpSouth:
39	                case BlockDirection.DownNorth:
40	                case BlockDirection.DownSouth:
41	                    addPos = new Vector3Int(blockSize.x, blockSize.z, blockSize.y);
42	                    break;
43	                case BlockDirection.UpEast:
44	                case BlockDirection.UpWest:
45	                case BlockDirection.DownEast:
46	                case BlockDirection.DownWest:
47	                    addPos = new Vector3Int(blockSize.y, blockSize.z, blockSize.x);
48	                    break;
49	                
50	                case BlockDirection.North:
51	                case BlockDirection.South:
52	                    addPos = new Vector3Int(blockSize.x, blockSize.y, blockSize.z);
53	                    break;
54	                case BlockDirection.East:
55	                case BlockDirection.West:
56	                    addPos = new Vector3Int(blockSize.z, blockSize.y, blockSize.x);
57	                    break;
58	            }
59	            
60	            // block sizeは1からとなっているが、ここで求めるのはブロックが占める範囲の最大値なので、-1している
61	            return addPos + originPos - Vector3Int.one;
62	        }
63	    }
64	}

